-- =============================================================================
-- 000005_fix_extend_session_end_time.up.sql
-- BUGFIX KRITIKAL: byoneExtendSession menghitung end_scheduled_at yang baru
-- dari NOW() + total booked_duration_minutes (bukan hanya menit tambahan).
-- Akibatnya waktu tersisa sesi jadi salah (bisa lebih besar ATAU lebih kecil
-- dari seharusnya) setiap kali sesi di-"Tambah", karena waktu yang sudah
-- berjalan sejak start_time ikut hilang/diabaikan dari perhitungan.
--
-- Fix: end_scheduled_at yang baru = end_scheduled_at LAMA (atau NOW jika sesi
-- belum ada jadwal akhir / sudah lewat waktu) + menit tambahan saja.
-- =============================================================================

CREATE OR REPLACE FUNCTION "__SP__ExtendSession"(p_session_id UUID, p_additional_minutes INTEGER, p_cash_received NUMERIC, p_pay_now BOOLEAN DEFAULT TRUE, p_voucher_code VARCHAR DEFAULT NULL, p_notes TEXT DEFAULT NULL) RETURNS TABLE(session_id UUID, session_booked_minutes INT, session_end_scheduled TIMESTAMPTZ, payment_id UUID, payment_amount NUMERIC, payment_discount NUMERIC, payment_total NUMERIC, payment_cash_received NUMERIC, payment_change NUMERIC, payment_voucher_id UUID, payment_status VARCHAR, payment_paid_at TIMESTAMPTZ) LANGUAGE plpgsql AS $$ DECLARE v_session sessions%ROWTYPE; v_payment_id UUID; v_amount NUMERIC(10,2); v_voucher_discount NUMERIC(10,2):=0; v_voucher_id UUID:=NULL; v_final_amount NUMERIC(10,2); v_change NUMERIC(10,2); v_new_booked INT; v_new_end TIMESTAMPTZ; v_now TIMESTAMPTZ:=NOW(); v_status VARCHAR; v_paid_at TIMESTAMPTZ; BEGIN SELECT * INTO v_session FROM sessions WHERE sessions.id=p_session_id FOR UPDATE; IF NOT FOUND THEN RAISE EXCEPTION 'SESSION_NOT_FOUND'; END IF; IF v_session.status!='active' THEN RAISE EXCEPTION 'SESSION_NOT_ACTIVE'; END IF; IF p_additional_minutes<=0 THEN RAISE EXCEPTION 'INVALID_DURATION: minimal 1 menit'; END IF; DECLARE v_new_total NUMERIC(10,2); v_old_total NUMERIC(10,2):=v_session.total_price; v_total_minutes INT:=v_session.booked_duration_minutes+p_additional_minutes; BEGIN SELECT pc.base_amount INTO v_new_total FROM "__SP__CalculatePrice"(v_session.console_id,v_total_minutes) pc; v_amount:=v_new_total-v_old_total; IF v_amount<0 THEN v_amount:=0; END IF; END; IF p_voucher_code IS NOT NULL AND TRIM(p_voucher_code)!='' THEN BEGIN SELECT va.voucher_id,va.discount_amount INTO v_voucher_id,v_voucher_discount FROM "__SP__ApplyVoucher"(p_voucher_code,v_amount) va; EXCEPTION WHEN OTHERS THEN v_voucher_discount:=0; v_voucher_id:=NULL; END; IF v_voucher_id IS NOT NULL THEN UPDATE vouchers SET usage_count=usage_count+1,updated_at=v_now WHERE id=v_voucher_id; END IF; END IF; IF v_voucher_discount>v_amount THEN v_voucher_discount:=v_amount; END IF; v_final_amount:=v_amount-v_voucher_discount; IF v_final_amount<0 THEN v_final_amount:=0; END IF; v_change:=GREATEST(p_cash_received-v_final_amount,0); v_new_booked:=v_session.booked_duration_minutes+p_additional_minutes; v_new_end:=GREATEST(COALESCE(v_session.end_scheduled_at,v_now),v_now)+(p_additional_minutes*INTERVAL'1 minute'); UPDATE sessions SET booked_duration_minutes=v_new_booked,end_scheduled_at=v_new_end,total_price=v_session.total_price+v_amount,updated_at=v_now WHERE sessions.id=p_session_id; IF p_pay_now THEN v_status:='paid'; v_paid_at:=v_now; ELSE v_status:='pending'; v_paid_at:=NULL; END IF; v_payment_id:=uuid_generate_v4(); INSERT INTO payments(id,session_id,amount,discount_amount,auto_discount_amount,total_payment,payment_method,payment_status,cash_received,change_amount,voucher_id,notes,paid_at,created_at,updated_at) VALUES(v_payment_id,p_session_id,v_amount,v_voucher_discount,0,v_final_amount,'cash',v_status,p_cash_received,v_change,v_voucher_id,p_notes,v_paid_at,v_now,v_now); RETURN QUERY SELECT p_session_id,v_new_booked,v_new_end,v_payment_id,v_amount,v_voucher_discount,v_final_amount,p_cash_received,v_change,v_voucher_id,v_status,v_paid_at; END; $$;

-- Perbaiki data sesi aktif yang end_scheduled_at-nya sudah terlanjur salah
-- akibat bug di atas (booked_duration_minutes tetap benar/kumulatif, hanya
-- end_scheduled_at yang perlu diselaraskan ulang terhadap start_time).
UPDATE sessions
SET end_scheduled_at = start_time + (booked_duration_minutes * INTERVAL '1 minute'), updated_at = NOW()
WHERE status = 'active' AND booked_duration_minutes > 0;
